/**
 * @summary Get appointments for a client
 */
export const getGetClientAppointmentsUrl = (clientId: number) => {
  return `/api/clients/${clientId}/appointments`;
};

export const getClientAppointments = async (
  clientId: number,
  options?: RequestInit,
): Promise<Appointment[]> => {
  return customFetch<Appointment[]>(getGetClientAppointmentsUrl(clientId), {
    ...options,
    method: "GET",
  });
};

export const getGetClientAppointmentsQueryKey = (clientId: number) => {
  return [`/api/clients/${clientId}/appointments`] as const;
};

export const getGetClientAppointmentsQueryOptions = <
  TData = Awaited<ReturnType<typeof getClientAppointments>>,
  TError = ErrorType<unknown>,
>(
  clientId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getClientAppointments>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetClientAppointmentsQueryKey(clientId);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getClientAppointments>>
  > = ({ signal }) =>
    getClientAppointments(clientId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!clientId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getClientAppointments>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetClientAppointmentsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getClientAppointments>>
>;
export type GetClientAppointmentsQueryError = ErrorType<unknown>;

/**
 * @summary Get appointments for a client
 */

export function useGetClientAppointments<
  TData = Awaited<ReturnType<typeof getClientAppointments>>,
  TError = ErrorType<unknown>,
>(
  clientId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getClientAppointments>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetClientAppointmentsQueryOptions(clientId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
